// models
export interface ICorCircleSketchProps {
  color?: TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | '';
  strokeWidth?: number;
  rotation?: number;
  animated?: boolean;
  animationDuration?: number;
  topPx?: number;
  leftPx?: number;
  dashed?: boolean;
  double?: boolean;
}

@Directive({
  selector: '[circleSketch]',
  standalone: true,
})
export class CorCircleSketchDirective {
  // inputs
  /** Whether to animate the circle drawing on init */
  // readonly animated = input<boolean | undefined>(undefined);
  readonly animated = input(COR_CIRCLE_SKETCH_DEFAULT.animated, { transform: booleanAttribute });

  /** Duration of the draw animation in ms */
  readonly animationDuration = input<number>(COR_CIRCLE_SKETCH_DEFAULT.animationDuration);

  /** Pass options object: <span [circleSketch]="{ color: '#2176ff', animated: true }"> */
  // readonly circleSketch = input<ICorCircleSketchProps | '' | true>('');

  /** Shorthand color override: <span circleSketch color="#2176ff"> */
  // readonly color = input<string | undefined>(undefined);
  readonly color = input<TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | ''>(COR_CIRCLE_SKETCH_DEFAULT.color);

  /** Dashed stroke variant */
  // readonly dashed = input<boolean | undefined>(undefined);
  readonly dashed = input(COR_CIRCLE_SKETCH_DEFAULT.dashed, { transform: booleanAttribute });

  /** Draw a second, lighter ellipse beneath for a double-stroke look */
  // readonly double = input<boolean | undefined>(undefined);
  readonly double = input(COR_CIRCLE_SKETCH_DEFAULT.double, { transform: booleanAttribute });

  readonly leftPx = input<number>(COR_CIRCLE_SKETCH_DEFAULT.leftPx);

  /** Rotation angle in degrees (default -2 for a natural tilt) */
  readonly rotation = input<number>(COR_CIRCLE_SKETCH_DEFAULT.rotation);

  /** Stroke weight override */
  readonly strokeWidth = input<number>(COR_CIRCLE_SKETCH_DEFAULT.strokeWidth);

  readonly topPx = input<number>(COR_CIRCLE_SKETCH_DEFAULT.topPx);

  // privates
  private readonly el = inject<ElementRef<HTMLElement>>(ElementRef);
  private readonly renderer = inject(Renderer2);
  colorVal = computed<string>(
    () => {
      const color: TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | '' = this.color();
      return !!color ? cssVar(`--clr-${color}`) : 'transparent';
    }
  );
  private svg: SVGSVGElement | null = null;
  private resizeObserver: ResizeObserver | null = null;

  /** Reactive merged options — recalculated whenever any input changes */
  private readonly opts = signal<Required<ICorCircleSketchProps>>(COR_CIRCLE_SKETCH_DEFAULT);

  // constructor
  constructor() {
    // afterRenderEffect runs after every render in which tracked signals change
    afterRenderEffect(
      () => {
        this.opts.set(this.#mergeOptions());
        this.#apply();
      }
    );
  }

  // lifecycles
  ngOnDestroy(): void {
    this.#teardown();
  }

  // utils
  #mergeOptions(): Required<ICorCircleSketchProps> {
    // const input = this.circleSketch();
    // const fromInput: ICorCircleSketchProps = !!input && typeof input === 'object' ? input : {};
    // console.log({ fromInput });
    const fromInput: ICorCircleSketchProps = {};

    return {
      color: this.colorVal() ?? fromInput.color ?? COR_CIRCLE_SKETCH_DEFAULT.color,
      strokeWidth: this.strokeWidth() ?? fromInput.strokeWidth ?? COR_CIRCLE_SKETCH_DEFAULT.strokeWidth,
      rotation: this.rotation() ?? fromInput.rotation ?? COR_CIRCLE_SKETCH_DEFAULT.rotation,
      animated: this.animated() ?? fromInput.animated ?? COR_CIRCLE_SKETCH_DEFAULT.animated,
      animationDuration: this.animationDuration() ?? fromInput.animationDuration ?? COR_CIRCLE_SKETCH_DEFAULT.animationDuration,
      dashed: this.dashed() ?? fromInput.dashed ?? COR_CIRCLE_SKETCH_DEFAULT.dashed,
      double: this.double() ?? fromInput.double ?? COR_CIRCLE_SKETCH_DEFAULT.double,
      topPx: this.topPx() ?? fromInput.topPx ?? COR_CIRCLE_SKETCH_DEFAULT.topPx,
      leftPx: this.leftPx() ?? fromInput.leftPx ?? COR_CIRCLE_SKETCH_DEFAULT.leftPx,
    };
  }

  #apply(): void {
    const host = this.el.nativeElement;

    // Ensure the host is positioned so the absolute SVG overlays correctly
    const pos = getComputedStyle(host).position;
    if (pos === 'static') {
      this.renderer.setStyle(host, 'position', 'relative');
    }
    this.renderer.setStyle(host, 'display', 'inline-block');
    this.renderer.setStyle(host, 'white-space', 'nowrap');

    this.#teardown();
    this.#buildSvg();

    // Watch for size changes (e.g. font-size transitions, window resize)
    this.resizeObserver = new ResizeObserver(() => this.#updateEllipses());
    this.resizeObserver.observe(host);
  }

  #buildSvg(): void {
    const host = this.el.nativeElement;
    const opts = this.opts();
    // console.log(opts.topPx * -1);
    // console.log(opts.leftPx * -1);

    const svg = this.renderer.createElement('svg', COR_CIRCLE_SKETCH_SVG_NS) as SVGSVGElement;
    this.renderer.setAttribute(svg, 'aria-hidden', 'true');
    this.renderer.setAttribute(svg, 'focusable', 'false');
    this.renderer.setStyle(svg, 'position', 'absolute');
    // this.renderer.setStyle(svg, 'top', '-12px');
    // this.renderer.setStyle(svg, 'left', '-14px');
    this.renderer.setStyle(svg, 'top', `${opts.topPx * -1}px`);
    this.renderer.setStyle(svg, 'left', `${opts.leftPx * -1}px`);
    // this.renderer.setStyle(svg, 'width', 'calc(100% + 28px)');
    // this.renderer.setStyle(svg, 'height', 'calc(100% + 24px)');
    this.renderer.setStyle(svg, 'height', `calc(100% + ${opts.topPx * 2}px)`);
    this.renderer.setStyle(svg, 'width', `calc(100% + ${opts.leftPx * 2}px)`);
    this.renderer.setStyle(svg, 'overflow', 'visible');
    this.renderer.setStyle(svg, 'pointer-events', 'none');

    // Double ellipse (secondary, lower opacity)
    if (!!opts.double) {
      const e2 = this.#createEllipse('cor-circle-sketch-e2');
      this.renderer.setAttribute(e2, 'opacity', '0.32');
      this.renderer.setAttribute(e2, 'stroke-width', String(opts.strokeWidth * 0.4));
      this.renderer.appendChild(svg, e2);
    }

    // Primary ellipse
    const e1 = this.#createEllipse('cor-circle-sketch-e1');
    this.renderer.setAttribute(e1, 'stroke-width', String(opts.strokeWidth));
    if (!!opts.dashed) {
      this.renderer.setAttribute(e1, 'stroke-dasharray', '6 3');
    }
    this.renderer.appendChild(svg, e1);

    this.renderer.appendChild(host, svg);
    this.svg = svg;

    // Sync geometry then optionally animate
    this.#updateEllipses();

    !!opts.animated && this.#animateIn();
  }

  #createEllipse(id: string): SVGEllipseElement {
    const el = this.renderer.createElement('ellipse', COR_CIRCLE_SKETCH_SVG_NS) as SVGEllipseElement;
    this.renderer.setAttribute(el, 'id', id);
    this.renderer.setAttribute(el, 'fill', 'none');
    this.renderer.setAttribute(el, 'stroke', this.opts().color);
    this.renderer.setAttribute(el, 'stroke-linecap', 'round');
    this.renderer.setAttribute(el, 'stroke-linejoin', 'round');
    return el;
  }

  #updateEllipses(): void {
    if (!this.svg) return;
    const host = this.el.nativeElement;
    const opts = this.opts();

    const w = host.offsetWidth + 28;
    const h = host.offsetHeight + 24;
    const cx = w / 2;
    const cy = h / 2;

    this.renderer.setAttribute(this.svg, 'viewBox', `0 0 ${w} ${h}`);

    const e1 = this.svg.getElementById('cor-circle-sketch-e1') as SVGEllipseElement | null;
    const e2 = this.svg.getElementById('cor-circle-sketch-e2') as SVGEllipseElement | null;

    if (!!e1) {
      const rx = cx - 8;
      const ry = cy - 4;
      this.#setEllipseGeometry(e1, cx, cy, rx, ry, opts.rotation, opts.color);
    }

    if (!!e2) {
      const rx = cx - 12;
      const ry = cy - 7;
      this.#setEllipseGeometry(e2, cx, cy, rx, ry, -opts.rotation, opts.color);
    }
  }

  #setEllipseGeometry(
    el: SVGEllipseElement,
    cx: number, cy: number,
    rx: number, ry: number,
    rotation: number,
    color: string,
  ): void {
    this.renderer.setAttribute(el, 'cx', String(cx));
    this.renderer.setAttribute(el, 'cy', String(cy));
    this.renderer.setAttribute(el, 'rx', String(Math.max(1, rx)));
    this.renderer.setAttribute(el, 'ry', String(Math.max(1, ry)));
    this.renderer.setAttribute(el, 'transform', `rotate(${rotation}, ${cx}, ${cy})`);
    this.renderer.setAttribute(el, 'stroke', color);
  }

  #animateIn(): void {
    if (!this.svg) return;
    const opts = this.opts();
    // const duration = `${opts.animationDuration}ms`;

    this.svg.querySelectorAll('ellipse').forEach((ellipse, i) => {
      // Use a large enough dasharray to cover any ellipse circumference
      const len = 2000;
      this.renderer.setAttribute(ellipse, 'stroke-dasharray', opts.dashed ? '6 3' : String(len));
      this.renderer.setAttribute(ellipse, 'stroke-dashoffset', String(len));

      ellipse.animate(
        [{ strokeDashoffset: len }, { strokeDashoffset: 0 }],
        {
          duration: opts.animationDuration,
          delay: i * 60,
          easing: 'cubic-bezier(0.4, 0, 0.2, 1)',
          fill: 'forwards',
        },
      );
    });
  }

  /** Remove the injected SVG and stop observing */
  #teardown(): void {
    this.resizeObserver?.disconnect();
    this.resizeObserver = null;

    if (this.svg) {
      this.svg.remove();
      this.svg = null;
    }
  }
}

