@Directive({
  selector: '[corFocus]',
  standalone: true,
})
export class CorFocusDirective {
  private readonly el = inject(ElementRef<HTMLInputElement>);

  readonly corFocus: InputSignalWithTransform<boolean, unknown> = input(true, {
    transform: booleanAttribute,
  });
  readonly focusDelay: InputSignal<number> = input(0);
  readonly focusSelect: InputSignalWithTransform<boolean, unknown> = input(
    false,
    { transform: booleanAttribute }
  );
  readonly focusDone: OutputEmitterRef<void> = output<void>();

  constructor() {
    effect(() => {
      const shouldFocus = this.corFocus();
      const delay = this.focusDelay();
      const select = this.focusSelect();

      if (!shouldFocus) return;

      // First focus attempt after the requested delay.
      setTimeout(() => {
        this.doFocus(select);

        // Second attempt 150ms later — wins the race against MatChipGrid
        // and any other Material init that steals focus after the first call.
        setTimeout(() => {
          this.doFocus(select);
          this.focusDone.emit();
        }, 150);
      }, delay);
    });
  }

  private doFocus(select: boolean): void {
    const nativeEl = this.el.nativeElement;
    if (!nativeEl?.isConnected) return;
    nativeEl.focus();
    if (select && typeof nativeEl.select === 'function') {
      nativeEl.select();
    }
  }
}

no-img.content:
/* 
Usage:

<img [src]="userAvatar" noImg />

<img [src]="productThumb" [noImg]="'assets/no-product.svg'" />
*/
@Directive({
  selector: 'img[noImg]',
  standalone: true
})
export class CorNoImageDirective {
  // Allow passing a specific SVG path, or use a default
  noImg = input<string>('/img/no-img.svg');

  constructor(private _el: ElementRef<HTMLImageElement>) { }

  @HostListener('error')
  onError() {
    this._el.nativeElement.src = this.noImg();
  }
}

